mapper.select:
select *
FROM jsh_depot_item
where 1=1


    and name like #{bindName}


    and type = #{type}



    and remark like #{bindRemark}

and ifnull(delete_flag,'0') !='1'

    limit #{offset},#{rows}

SELECT
COUNT(id)
FROM jsh_depot_item
WHERE 1=1


    and name like #{bindName}


    and type = #{type}



    and remark like #{bindRemark}

and ifnull(delete_flag,'0') !='1'

select tb.* from
(select dh.number,me.bar_code,m.name material_name,dh.type,dh.sub_type,
case
    when type='入库' then ifnull(di.basic_number,0)
    when type='出库' then 0-di.basic_number
    when dh.sub_type='组装单' and di.material_type='组合件' then ifnull(di.basic_number,0)
    when dh.sub_type='组装单' and di.material_type='普通子件' then 0-di.basic_number
    when dh.sub_type='拆卸单' and di.material_type='普通子件' then ifnull(di.basic_number,0)
    when dh.sub_type='拆卸单' and di.material_type='组合件' then 0-di.basic_number
    when dh.sub_type='盘点复盘' then ifnull(di.basic_number,0)
    else 0
end
as b_num,
(select name from jsh_depot d where d.id=di.depot_id and ifnull(d.delete_flag,'0') !='1') as depotName,
date_format(dh.oper_time,'%Y-%m-%d %H:%i:%S') as oTime
from jsh_depot_head dh
left join jsh_depot_item di on dh.id=di.header_id and ifnull(di.delete_flag,'0') !='1'
left join jsh_material m on di.material_id=m.id and ifnull(m.delete_flag,'0') !='1'
left join jsh_material_extend me on me.id=di.material_extend_id and ifnull(me.delete_Flag,'0') !='1'
where (dh.type!='其它'
or (dh.type='其它' and dh.sub_type='组装单')
or (dh.type='其它' and dh.sub_type='拆卸单')
or (dh.type='其它' and dh.sub_type='盘点复盘'))

    and di.depot_id in (
    #{depotId}
    )


    and di.sku = #{sku}


    and di.batch_number = #{batchNumber}



    and dh.number like #{bindNumber}


    and dh.oper_time >= #{beginTime}


    and dh.oper_time <= #{endTime}

and di.material_id = #{mId}
and ifnull(dh.delete_flag,'0') !='1'
union all
--单独构造记录：调拨入库
select dh.number,me.bar_code,m.name material_name,dh.type,dh.sub_type,
ifnull(di.basic_number,0) as b_num,
(select concat(name,'[调入]') from jsh_depot d where d.id=di.another_depot_id and ifnull(d.delete_flag,'0') !='1') as depotName,
date_format(dh.oper_time,'%Y-%m-%d %H:%i:%S') as oTime
from jsh_depot_head dh
left join jsh_depot_item di on dh.id=di.header_id and ifnull(di.delete_flag,'0') !='1'
left join jsh_material m on di.material_id=m.id and ifnull(m.delete_flag,'0') !='1'
left join jsh_material_extend me on me.id=di.material_extend_id and ifnull(me.delete_Flag,'0') !='1'
where dh.type='出库' and (dh.sub_type='调拨' or dh.sub_type='隔离')

    and di.another_depot_id in (
    #{depotId}
    )


    and di.sku = #{sku}


    and di.batch_number = #{batchNumber}



    and dh.number like #{bindNumber}


    and dh.oper_time >= #{beginTime}


    and dh.oper_time <= #{endTime}

and di.material_id = #{mId}
and ifnull(dh.delete_flag,'0') !='1') tb
order by tb.oTime desc

    limit #{offset},#{rows}

select count(tb.number) from
(select dh.number from jsh_depot_head dh
left JOIN jsh_depot_item di on dh.id=di.header_id and ifnull(di.delete_flag,'0') !='1'
where (dh.type!='其它'
or (dh.type='其它' and dh.sub_type='组装单')
or (dh.type='其它' and dh.sub_type='拆卸单')
or (dh.type='其它' and dh.sub_type='盘点复盘'))

    and di.depot_id in (
    #{depotId}
    )


    and di.sku = #{sku}


    and di.batch_number = #{batchNumber}



    and dh.number like #{bindNumber}


    and dh.oper_time >= #{beginTime}


    and dh.oper_time <= #{endTime}

and di.material_id =#{mId}
and ifnull(dh.delete_flag,'0') !='1'
union all
--单独构造记录：调拨入库
select dh.number from jsh_depot_head dh
left join jsh_depot_item di on dh.id=di.header_id and ifnull(di.delete_flag,'0') !='1'
where dh.type='出库' and (dh.sub_type='调拨' or dh.sub_type='隔离')

    and di.another_depot_id in (
    #{depotId}
    )


    and di.sku = #{sku}


    and di.batch_number = #{batchNumber}



    and dh.number like #{bindNumber}


    and dh.oper_time >= #{beginTime}


    and dh.oper_time <= #{endTime}

and di.material_id = #{mId}
and ifnull(dh.delete_flag,'0') !='1') tb

select tb.* from
(select dh.number,me.bar_code,m.name material_name,dh.type,dh.sub_type,
ifnull(di.basic_number,0) as b_num,
(select name from jsh_depot d where d.id=di.depot_id and ifnull(d.delete_flag,'0') !='1') as depotName,
date_format(dh.oper_time,'%Y-%m-%d %H:%i:%S') as oTime
from jsh_depot_head dh
left join jsh_depot_item di on dh.id=di.header_id and ifnull(di.delete_flag,'0') !='1'
left join jsh_material m on di.material_id=m.id and ifnull(m.delete_flag,'0') !='1'
left join jsh_material_extend me on me.id=di.material_extend_id and ifnull(me.delete_Flag,'0') !='1'
where (dh.type='入库' and dh.sub_type='生产')

    and di.depot_id in (
    #{depotId}
    )


    and dh.link_number in (
    #{productionOrderId}
    )


    and di.sku = #{sku}


    and di.batch_number = #{batchNumber}



    and dh.number like #{bindNumber}


    and dh.oper_time >= #{beginTime}


    and dh.oper_time <= #{endTime}

and di.material_id = #{mId}
and ifnull(dh.delete_flag,'0') !='1') tb
order by tb.oTime desc

    limit #{offset},#{rows}

select count(tb.number) from
(select dh.number from jsh_depot_head dh
left JOIN jsh_depot_item di on dh.id=di.header_id and ifnull(di.delete_flag,'0') !='1'
where (dh.type='入库' and dh.sub_type='生产')

    and di.depot_id in (
    #{depotId}
    )


    and dh.link_number in (
    #{productionOrderId}
    )


    and di.sku = #{sku}


    and di.batch_number = #{batchNumber}



    and dh.number like #{bindNumber}


    and dh.oper_time >= #{beginTime}


    and dh.oper_time <= #{endTime}

and di.material_id =#{mId}
and ifnull(dh.delete_flag,'0') !='1') tb

select m.id MId, me.bar_code, m.name MName, m.mat MMat, m.model MModel, m.color_code MColorCode, m.other_field1 MOtherField1,m.other_field2 MOtherField2,m.other_field3 MOtherField3, m.other_field4 MOtherField4,m.other_field5 MOtherField5,m.other_field6 MOtherField6, m.other_field7 MOtherField7,m.other_field8 MOtherField8,m.other_field9 MOtherField9, m.other_field10 MOtherField10, concat_ws('', m.unit, u.basic_unit) MaterialUnit, m.color MColor, m.unit_id, u.name unit_name, ifnull(me.purchase_decimal,0) purchase_decimal from jsh_material m left join jsh_material_extend me on me.material_id=m.id and ifnull(me.delete_Flag,'0') !='1' left join jsh_depot_item di on di.material_id=m.id and ifnull(di.delete_Flag,'0') !='1' left join jsh_depot_head dh on di.header_id=dh.id and ifnull(dh.delete_flag,'0') !='1' left join jsh_unit u on m.unit_id=u.id and ifnull(u.delete_Flag,'0') !='1' where 1=1 and me.default_flag=1
and (me.bar_code like #{bindKey} or m.name like #{bindKey} or m.color_code like #{bindKey} or m.other_field5 like #{bindKey} or m.color like #{bindKey} or m.model like #{bindKey} or m.mat like #{bindKey})
and dh.oper_time <= #{endTime}
and ifnull(m.delete_flag,'0') !='1' group by m.id order by m.id desc
limit #{offset},#{rows}

select m.id MId, me.bar_code, m.name MName, m.mat MMat, m.model MModel, m.color_code MColorCode, m.other_field1 MOtherField1,m.other_field2 MOtherField2,m.other_field3 MOtherField3, m.other_field4 MOtherField4,m.other_field5 MOtherField5,m.other_field6 MOtherField6, m.other_field7 MOtherField7,m.other_field8 MOtherField8,m.other_field9 MOtherField9, m.other_field10 MOtherField10, concat_ws('', m.unit, u.basic_unit) MaterialUnit, m.color MColor, u.name unit_name from jsh_material m left join jsh_depot_item di on di.material_id=m.id and ifnull(di.delete_Flag,'0') !='1' left join jsh_material_extend me on me.id=di.material_extend_id and ifnull(me.delete_Flag,'0') !='1' left join jsh_depot_head dh on di.header_id=dh.id and ifnull(dh.delete_flag,'0') !='1' left join jsh_unit u on m.unit_id=u.id and ifnull(u.delete_Flag,'0') !='1' where 1=1
and (me.bar_code like #{bindKey} or m.name like #{bindKey} or m.color_code like #{bindKey} or m.other_field5 like #{bindKey} or m.color like #{bindKey} or m.model like #{bindKey} or m.mat like #{bindKey})
and (dh.sub_type = '采购' or dh.sub_type = '采购退货')
and (dh.sub_type = '销售' or dh.sub_type = '销售退货' or dh.sub_type = '零售' or dh.sub_type = '零售退货')
and dh.oper_time >= #{beginTime}
and dh.oper_time <= #{endTime}
and dh.creator in (
#{creator}
)
and ifnull(m.delete_flag,'0') !='1' group by m.id order by m.id desc
limit #{offset},#{rows}

select count(1) from (select m.id
from jsh_material m
left join jsh_depot_item di on di.material_id=m.id  and ifnull(m.delete_Flag,'0') !='1'
left join jsh_material_extend me on me.id=di.material_extend_id  and ifnull(me.delete_Flag,'0') !='1'
left join jsh_depot_head dh on di.header_id=dh.id  and ifnull(dh.delete_flag,'0') !='1'
where 1=1


    and (me.bar_code like #{bindKey} or m.name like #{bindKey} or m.color_code like #{bindKey}
    or m.other_field5 like #{bindKey} or m.color like #{bindKey} or m.model like #{bindKey}
    or m.mat like #{bindKey})


    and (dh.sub_type = '采购' or dh.sub_type = '采购退货')


    and (dh.sub_type = '销售' or dh.sub_type = '销售退货' or dh.sub_type = '零售' or dh.sub_type = '零售退货')


    and dh.oper_time >= #{beginTime}


    and dh.oper_time <= #{endTime}


    and dh.creator in (

        #{creator}

    )

and ifnull(di.delete_flag,'0') !='1'
group by m.id) cc

select m.id MId, me.bar_code, m.name MName, m.mat MMat, m.model MModel, m.color_code MColorCode, m.other_field1 MOtherField1,m.other_field2 MOtherField2,m.other_field3 MOtherField3, m.other_field4 MOtherField4,m.other_field5 MOtherField5,m.other_field6 MOtherField6, m.other_field7 MOtherField7,m.other_field8 MOtherField8,m.other_field9 MOtherField9, m.other_field10 MOtherField10, concat_ws('', m.unit, u.basic_unit) MaterialUnit, m.color MColor, u.name unit_name from jsh_material m left join jsh_depot_item di on di.material_id=m.id and ifnull(di.delete_Flag,'0') !='1' left join jsh_material_extend me on me.id=di.material_extend_id and ifnull(me.delete_Flag,'0') !='1' left join jsh_depot_head dh on di.header_id=dh.id and ifnull(dh.delete_flag,'0') !='1' left join jsh_unit u on m.unit_id=u.id and ifnull(u.delete_Flag,'0') !='1' where 1=1 and dh.sub_type = '生产单'
and (me.bar_code like #{bindKey} or m.name like #{bindKey} or m.color_code like #{bindKey} or m.other_field5 like #{bindKey} or m.color like #{bindKey} or m.model like #{bindKey} or m.mat like #{bindKey})
and dh.plan_start_time >= #{beginTime}
and dh.plan_start_time <= #{endTime}
and dh.creator in (
#{creator}
)
and ifnull(m.delete_flag,'0') !='1' group by m.id order by m.id desc
limit #{offset},#{rows}

select count(1) from (select m.id
from jsh_material m
left join jsh_depot_item di on di.material_id=m.id  and ifnull(m.delete_Flag,'0') !='1'
left join jsh_material_extend me on me.id=di.material_extend_id  and ifnull(me.delete_Flag,'0') !='1'
left join jsh_depot_head dh on di.header_id=dh.id  and ifnull(dh.delete_flag,'0') !='1'
where 1=1
and dh.sub_type = '生产单'


    and (me.bar_code like #{bindKey} or m.name like #{bindKey} or m.color_code like #{bindKey}
    or m.other_field5 like #{bindKey} or m.color like #{bindKey} or m.model like #{bindKey}
    or m.mat like #{bindKey})


    and dh.plan_start_time >= #{beginTime}


    and dh.plan_start_time <= #{endTime}


    and dh.creator in (

        #{creator}

    )

and ifnull(di.delete_flag,'0') !='1'
group by m.id) cc

select ifnull(sum(basic_number),0) as BasicNumber from jsh_depot_item di,jsh_depot_head dh
where di.header_id = dh.id
and dh.type='入库' and dh.sub_type='生产'

    and dh.link_number in (

        #{productionOrderNumber}

    )

and di.material_id =#{MId}
and ifnull(dh.delete_flag,'0') !='1'
and ifnull(di.delete_flag,'0') !='1'

select ifnull(sum(basic_number),0) as BasicNumber from jsh_depot_item di,jsh_depot_head dh
where di.header_id = dh.id
and dh.type=#{type} and dh.sub_type=#{subType}
and di.material_id =#{MId}
and dh.oper_time >= #{beginTime}
and dh.oper_time <= #{endTime}

    and dh.creator in (

        #{creator}

    )

and ifnull(dh.delete_flag,'0') !='1'
and ifnull(di.delete_flag,'0') !='1'

select ifnull(sum(all_price),0) as AllPrice from jsh_depot_item di,jsh_depot_head dh
where di.header_id = dh.id
and dh.type=#{type} and dh.sub_type=#{subType}
and di.material_id =#{MId}
and dh.oper_time >= #{beginTime}
and dh.oper_time <= #{endTime}

    and dh.creator in (

        #{creator}

    )

and ifnull(dh.delete_flag,'0') !='1'
and ifnull(di.delete_flag,'0') !='1'

select ifnull(sum(dh.other_money),0) as AllPrice from jsh_depot_item di,jsh_depot_head dh
where di.header_id = dh.id
and dh.type=#{type} and dh.sub_type=#{subType}
and di.material_id =#{MId}
and dh.oper_time >= #{beginTime}
and dh.oper_time <= #{endTime}

    and dh.creator in (

        #{creator}

    )

and ifnull(dh.delete_flag,'0') !='1'
and ifnull(di.delete_flag,'0') !='1'

select ifnull(sum(discount_last_money),0) as allMoney from
(select distinct dh.id, dh.discount_last_money
from jsh_depot_head dh
left join jsh_depot_item di on dh.id = di.header_id
where 1=1
and di.id is not null
and dh.type=#{type} and dh.sub_type=#{subType}
and dh.oper_time >= #{beginTime}
and dh.oper_time <= #{endTime}

    and dh.creator in (

        #{creator}

    )

and ifnull(dh.delete_flag,'0') !='1'
and ifnull(di.delete_flag, '0') != '1') tb

select ifnull(sum(total_price),0) as allMoney from
(select distinct dh.id, dh.total_price
from jsh_depot_head dh
left join jsh_depot_item di on dh.id = di.header_id
where 1=1
and di.id is not null
and dh.type=#{type} and dh.sub_type=#{subType}
and dh.oper_time >= #{beginTime}
and dh.oper_time <= #{endTime}

    and dh.creator in (

        #{creator}

    )

and ifnull(dh.delete_flag,'0') !='1'
and ifnull(di.delete_flag, '0') != '1') tb

select ifnull(sum(di.basic_number),0) stockCheckSum from jsh_depot_head dh
left JOIN jsh_depot_item di on dh.id=di.header_id
where 1=1

    and di.material_id=#{mId}

and dh.sub_type='盘点复盘'

    and di.depot_id in

        #{item}



    and dh.oper_time >= #{beginTime}


    and dh.oper_time <= #{endTime}

and ifnull(dh.delete_flag,'0') !='1'
and ifnull(di.delete_flag,'0') !='1'

select sum(case when dh.type='入库' then di.basic_number else 0 end) as inTotal, sum(case when dh.type='出库' and dh.sub_type!='调拨' and dh.sub_type!='隔离' then di.basic_number else 0 end) as outTotal, sum(case when (dh.sub_type='调拨' or dh.sub_type='隔离') then di.basic_number else 0 end) as transfInTotal, sum(case when (dh.sub_type='调拨' or dh.sub_type='隔离') then di.basic_number else 0 end) as transfOutTotal, sum(case when dh.sub_type='组装单' and di.material_type='组合件' then di.basic_number else 0 end) as assemInTotal, sum(case when dh.sub_type='组装单' and di.material_type='普通子件' then di.basic_number else 0 end) as assemOutTotal, sum(case when dh.sub_type='拆卸单' and di.material_type='普通子件' then di.basic_number else 0 end) as disAssemInTotal, sum(case when dh.sub_type='拆卸单' and di.material_type='组合件' then di.basic_number else 0 end) as disAssemOutTotal from jsh_depot_head dh left join jsh_depot_item di on dh.id=di.header_id and ifnull(di.delete_flag,'0') !='1' where 1=1 and ifnull(dh.delete_flag,'0') !='1' and di.material_extend_id=#{meId} and ifnull(di.sku,'') !=''
and dh.oper_time >= #{beginTime}
and dh.oper_time <= #{endTime}

select sum(case when dh.type='入库' then di.basic_number else 0 end) as inTotal, sum(case when dh.type='出库' and dh.sub_type!='调拨' and dh.sub_type!='隔离' then di.basic_number else 0 end) as outTotal, sum(case when (dh.sub_type='调拨' or dh.sub_type='隔离') then di.basic_number else 0 end) as transfInTotal, sum(case when (dh.sub_type='调拨' or dh.sub_type='隔离') then di.basic_number else 0 end) as transfOutTotal, sum(case when dh.sub_type='组装单' and di.material_type='组合件' then di.basic_number else 0 end) as assemInTotal, sum(case when dh.sub_type='组装单' and di.material_type='普通子件' then di.basic_number else 0 end) as assemOutTotal, sum(case when dh.sub_type='拆卸单' and di.material_type='普通子件' then di.basic_number else 0 end) as disAssemInTotal, sum(case when dh.sub_type='拆卸单' and di.material_type='组合件' then di.basic_number else 0 end) as disAssemOutTotal from jsh_depot_head dh left join jsh_depot_item di on dh.id=di.header_id and ifnull(di.delete_flag,'0') !='1' where 1=1 and ifnull(dh.delete_flag,'0') !='1' and di.material_id=#{mId}
and dh.oper_time >= #{beginTime}
and dh.oper_time <= #{endTime}

select dep.id,dep.header_id,dep.material_id,dep.material_unit,dep.oper_number, dep.basic_number,dep.unit_price,dep.tax_unit_price,dep.all_price,dep.remark, dep.depot_id,dep.another_depot_id,dep.tax_rate, dep.tax_money,dep.tax_last_money,dep.material_type from jsh_depot_item dep,jsh_material mat where 1=1
and dep.header_id = #{depotheadId}
and dep.material_id=mat.id and ifnull(dep.delete_flag,'0') !='1' and ifnull(mat.delete_flag,'0') !='1'

mapper.update:
update jsh_depot_item set delete_flag='1' where 1=1 and header_id in (
#{depotheadId}
)

update jsh_depot_item
set delete_flag='1'
where 1=1
and id in (

    #{id}

)

