where di.material_extend_id=#{meId}
and di.link_id=#{linkId}
and ifnull(di.delete_flag,'0') !='1'
and di.header_id
in
(
select dh.id from jsh_depot_head dh
where
dh.link_number=#{linkNumber}
and ifnull(dh.delete_flag,'0') !='1'

    and dh.sub_type=#{goToType}

)

select ifnull(sum(di.basic_number),0) from jsh_depot_item di
where di.material_extend_id=#{meId}
and ifnull(di.delete_flag,'0') !='1'
and di.link_id
in
(

    select di.id from jsh_depot_item di
    where di.material_extend_id=#{meId}
    and di.link_id=#{linkId}
    and ifnull(di.delete_flag,'0') !='1'
    and di.header_id
    in
    (

        select dh.id from jsh_depot_head dh
        where dh.link_number=#{linkNumber}
        and ifnull(dh.delete_flag,'0') !='1'
    )
)
and di.header_id
in
(
    select dh.id from jsh_depot_head dh
    where ifnull(dh.delete_flag,'0') !='1'
    and dh.link_number
    in
    (

        select dh.number from jsh_depot_head dh
        where dh.link_number=#{linkNumber}
        and ifnull(dh.delete_flag,'0') !='1'
    )

        and dh.sub_type=#{goToType}

)

select ifnull(sum(di.basic_number),0) from jsh_depot_item di
where di.material_extend_id=#{meId}
and di.link_id=#{linkId}
and ifnull(di.delete_flag,'0') !='1'
and di.header_id
in
(
select dh.id from jsh_depot_head dh
where
dh.link_number=#{linkNumber}
and dh.id!=#{currentHeaderId}
and ifnull(dh.delete_flag,'0') !='1'

    and dh.sub_type=#{goToType}

)

select ifnull(sum(di.basic_number),0) from jsh_depot_item di
where di.material_extend_id=#{meId}
and ifnull(di.delete_flag,'0') !='1'
and di.link_id
in
(

    select di.id from jsh_depot_item di
    where di.material_extend_id=#{meId}
    and di.link_id=#{linkId}
    and ifnull(di.delete_flag,'0') !='1'
    and di.header_id
    in
    (

        select dh.id from jsh_depot_head dh
        where dh.link_number=#{linkNumber}
        and ifnull(dh.delete_flag,'0') !='1'
    )
)
and di.header_id
in
(
    select dh.id from jsh_depot_head dh
    where ifnull(dh.delete_flag,'0') !='1'
    and dh.id!=#{currentHeaderId}
    and dh.link_number
    in
    (

        select dh.number from jsh_depot_head dh
        where dh.link_number=#{linkNumber}
        and ifnull(dh.delete_flag,'0') !='1'
    )

        and dh.sub_type=#{goToType}

)

select id, bar_code, name, color_code, model, unit_id, oper_time, GROUP_CONCAT(distinct(NULLIF(sn,''))) as sn_list, commodity_unit, batch_number, expiration_date, sum(basic_number) total_num from (select di.batch_number id, me.bar_code, m.name, m.color_code, m.model, m.unit_id, me.commodity_unit, di.batch_number,di.expiration_date, dh.oper_time, case when (dh.type='入库'
or (dh.type='出库' and (dh.sub_type='调拨' or dh.sub_type='隔离') and di.another_depot_id= #{depotId}) ) then di.sn_list when dh.type='出库' then '' end as sn, di.basic_number*(case
when (dh.type='入库'
or (dh.type='出库' and (dh.sub_type='调拨' or dh.sub_type='隔离') and di.another_depot_id= #{depotId}) ) then 1 when dh.type='出库' then -1 end) as basic_number from jsh_depot_head dh left join jsh_depot_item di on dh.id=di.header_id left join jsh_material m on m.id=di.material_id and ifnull(m.delete_flag, '0') != '1' left join jsh_material_extend me on me.material_id=m.id and ifnull(me.delete_flag,'0') !='1' where me.bar_code= #{barCode}
and di.batch_number like #{bindName}
and (di.depot_id= #{depotId} or di.another_depot_id= #{depotId})
and di.batch_number= #{batchNumber}
and dh.number!= #{number}
and di.delete_flag!=1) tb group by batch_number order by oper_time asc

select count(1) from jsh_depot_item di
where di.material_id=#{mId} and di.depot_id=#{depotId}
and ifnull(di.delete_flag,'0') !='1'
